-- ----------------------------------------------------------------------------
-- AppUsers: Table: AppUsers
-- ----------------------------------------------------------------------------
CREATE TABLE app_users (
  app_user_id                         TEXT                 PRIMARY KEY,
  contact_name                        TEXT                ,
  email_address                       TEXT                ,
  phone_number                        TEXT                ,
  role                                TEXT                ,
  notes                               TEXT                
);
COMMENT ON TABLE app_users IS 'Table: AppUsers';

-- ----------------------------------------------------------------------------
-- Clients: Table: Clients
-- ----------------------------------------------------------------------------
CREATE TABLE clients (
  client_id                           TEXT                 PRIMARY KEY,
  name                                TEXT                ,                     -- Human-readable customer name.
  notes                               TEXT                ,                     -- Free-form notes about the customer.
  category                            TEXT                ,
  status                              TEXT                ,                     -- Link to the customer's current Status in the Statuses table.
  email                               TEXT                ,                     -- Primary email address for the customer.
  phone                               TEXT                ,                     -- Primary phone number for the customer.
  company_name                        TEXT                ,                     -- Company the customer represents, if applicable.
  addresses                           TEXT                ,
  created_at                          TIMESTAMPTZ                               -- Timestamp when the customer record was created.
);
COMMENT ON TABLE clients IS 'Table: Clients';
COMMENT ON COLUMN clients.name IS 'Human-readable customer name.';
COMMENT ON COLUMN clients.notes IS 'Free-form notes about the customer.';
COMMENT ON COLUMN clients.status IS 'Link to the customer''s current Status in the Statuses table.';
COMMENT ON COLUMN clients.email IS 'Primary email address for the customer.';
COMMENT ON COLUMN clients.phone IS 'Primary phone number for the customer.';
COMMENT ON COLUMN clients.company_name IS 'Company the customer represents, if applicable.';
COMMENT ON COLUMN clients.created_at IS 'Timestamp when the customer record was created.';

-- ----------------------------------------------------------------------------
-- ClientApprovals: Table: ClientApprovals
-- ----------------------------------------------------------------------------
CREATE TABLE client_approvals (
  client_approval_id                  TEXT                 PRIMARY KEY,
  client                              TEXT                ,
  approved_by                         TEXT                ,
  notes                               TEXT                
);
COMMENT ON TABLE client_approvals IS 'Table: ClientApprovals';

-- ----------------------------------------------------------------------------
-- ClientCategories: Table: ClientCategories
-- ----------------------------------------------------------------------------
CREATE TABLE client_categories (
  client_categorie_id                 TEXT                 PRIMARY KEY,
  name                                TEXT                ,
  discount                            NUMERIC             ,
  notes                               TEXT                
);
COMMENT ON TABLE client_categories IS 'Table: ClientCategories';

-- ----------------------------------------------------------------------------
-- Statuses: Table: Statuses
-- ----------------------------------------------------------------------------
CREATE TABLE statuses (
  statuse_id                          TEXT                 PRIMARY KEY,
  display_name                        TEXT                ,                     -- Human-readable display name of the status (e.g., "On-Hold", "In-Review").
  description                         TEXT                ,                     -- Free-form description of what this status means and when it applies.
  is_blocking                         BOOLEAN             ,                     -- True when customers in this status should be considered stopped (blocked from progressing).
  sort_order                          INTEGER                                   -- Display order for this status in lists.
);
COMMENT ON TABLE statuses IS 'Table: Statuses';
COMMENT ON COLUMN statuses.display_name IS 'Human-readable display name of the status (e.g., "On-Hold", "In-Review").';
COMMENT ON COLUMN statuses.description IS 'Free-form description of what this status means and when it applies.';
COMMENT ON COLUMN statuses.is_blocking IS 'True when customers in this status should be considered stopped (blocked from progressing).';
COMMENT ON COLUMN statuses.sort_order IS 'Display order for this status in lists.';

-- ----------------------------------------------------------------------------
-- Products: Table: Products
-- ----------------------------------------------------------------------------
CREATE TABLE products (
  product_id                          TEXT                 PRIMARY KEY,
  sku                                 TEXT                ,                     -- Stock-keeping unit identifier for the product. The natural compound key.
  display_name                        TEXT                ,                     -- Human-readable product name shown in catalogs and orders.
  description                         TEXT                ,                     -- Long-form product description.
  unit_price                          NUMERIC             ,                     -- Default list price per unit.
  cost                                NUMERIC             ,                     -- Internal cost per unit.
  is_active                           BOOLEAN             ,                     -- True when the product is currently sellable.
  inventory_adjustments               TEXT                
);
COMMENT ON TABLE products IS 'Table: Products';
COMMENT ON COLUMN products.sku IS 'Stock-keeping unit identifier for the product. The natural compound key.';
COMMENT ON COLUMN products.display_name IS 'Human-readable product name shown in catalogs and orders.';
COMMENT ON COLUMN products.description IS 'Long-form product description.';
COMMENT ON COLUMN products.unit_price IS 'Default list price per unit.';
COMMENT ON COLUMN products.cost IS 'Internal cost per unit.';
COMMENT ON COLUMN products.is_active IS 'True when the product is currently sellable.';

-- ----------------------------------------------------------------------------
-- Invoices: Table: Invoices
-- ----------------------------------------------------------------------------
CREATE TABLE invoices (
  invoice_id                          TEXT                 PRIMARY KEY,
  invoice_number                      TEXT                ,                     -- Sequential or human-assigned order identifier (e.g. '1001'). Combined with Customer to form the order's natural key.
  client                              TEXT                ,                     -- Link to the Customer who placed this order.
  order_date                          TIMESTAMPTZ         ,                     -- When the order was placed.
  order_status                        TEXT                ,                     -- Lifecycle state of the order.
  shipping_address                    TEXT                ,                     -- Where this specific order ships to.
  billing_address                     TEXT                ,                     -- Billing address used for this specific order.
  notes                               TEXT                ,                     -- Free-form notes about this order.
  tax_rate                            NUMERIC                                   -- Sales tax rate applied to this order.
);
COMMENT ON TABLE invoices IS 'Table: Invoices';
COMMENT ON COLUMN invoices.invoice_number IS 'Sequential or human-assigned order identifier (e.g. ''1001''). Combined with Customer to form the order''s natural key.';
COMMENT ON COLUMN invoices.client IS 'Link to the Customer who placed this order.';
COMMENT ON COLUMN invoices.order_date IS 'When the order was placed.';
COMMENT ON COLUMN invoices.order_status IS 'Lifecycle state of the order.';
COMMENT ON COLUMN invoices.shipping_address IS 'Where this specific order ships to.';
COMMENT ON COLUMN invoices.billing_address IS 'Billing address used for this specific order.';
COMMENT ON COLUMN invoices.notes IS 'Free-form notes about this order.';
COMMENT ON COLUMN invoices.tax_rate IS 'Sales tax rate applied to this order.';

-- ----------------------------------------------------------------------------
-- InvoiceLineItems: Table: InvoiceLineItems
-- ----------------------------------------------------------------------------
CREATE TABLE invoice_line_items (
  invoice_line_item_id                TEXT                 PRIMARY KEY,
  line_number                         TEXT                ,                     -- Position of this line within its parent Order (e.g. '1', '2'). Combined with Order to form the line item's natural key.
  invoice                             TEXT                ,                     -- Link to the parent Order this line item belongs to.
  product                             TEXT                ,                     -- Link to the Product being ordered on this line.
  quantity                            INTEGER             ,                     -- Number of units ordered on this line.
  notes                               TEXT                                      -- Free-form notes about this line item.
);
COMMENT ON TABLE invoice_line_items IS 'Table: InvoiceLineItems';
COMMENT ON COLUMN invoice_line_items.line_number IS 'Position of this line within its parent Order (e.g. ''1'', ''2''). Combined with Order to form the line item''s natural key.';
COMMENT ON COLUMN invoice_line_items.invoice IS 'Link to the parent Order this line item belongs to.';
COMMENT ON COLUMN invoice_line_items.product IS 'Link to the Product being ordered on this line.';
COMMENT ON COLUMN invoice_line_items.quantity IS 'Number of units ordered on this line.';
COMMENT ON COLUMN invoice_line_items.notes IS 'Free-form notes about this line item.';

-- ----------------------------------------------------------------------------
-- InventoryAdjustments: Table: InventoryAdjustments
-- ----------------------------------------------------------------------------
CREATE TABLE inventory_adjustments (
  inventory_adjustment_id             TEXT                 PRIMARY KEY,
  product                             TEXT                ,
  date                                TIMESTAMPTZ         ,
  adjustment_type                     TEXT                ,
  quantity                            INTEGER             ,
  reason                              TEXT                ,
  notes                               TEXT                ,
  adjusted_by                         TEXT                
);
COMMENT ON TABLE inventory_adjustments IS 'Table: InventoryAdjustments';

-- ----------------------------------------------------------------------------
-- Payments: Table: Payments
-- ----------------------------------------------------------------------------
CREATE TABLE payments (
  payment_id                          TEXT                 PRIMARY KEY,
  payment_number                      TEXT                ,                     -- Sequential payment identifier within the parent Order (e.g. '1', '2'). Combined with Order to form the payment's natural key.
  invoice                             TEXT                ,                     -- Link to the Order this payment is being applied to.
  payment_date                        TIMESTAMPTZ         ,                     -- When the payment was received.
  payment_method                      TEXT                ,                     -- How the payment was made.
  transaction_id                      TEXT                ,                     -- External processor transaction identifier.
  notes                               TEXT                ,                     -- Free-form notes about this payment.
  amount                              NUMERIC             ,                     -- Amount paid.
  payment_status                      TEXT                                      -- Lifecycle state of the payment.
);
COMMENT ON TABLE payments IS 'Table: Payments';
COMMENT ON COLUMN payments.payment_number IS 'Sequential payment identifier within the parent Order (e.g. ''1'', ''2''). Combined with Order to form the payment''s natural key.';
COMMENT ON COLUMN payments.invoice IS 'Link to the Order this payment is being applied to.';
COMMENT ON COLUMN payments.payment_date IS 'When the payment was received.';
COMMENT ON COLUMN payments.payment_method IS 'How the payment was made.';
COMMENT ON COLUMN payments.transaction_id IS 'External processor transaction identifier.';
COMMENT ON COLUMN payments.notes IS 'Free-form notes about this payment.';
COMMENT ON COLUMN payments.amount IS 'Amount paid.';
COMMENT ON COLUMN payments.payment_status IS 'Lifecycle state of the payment.';

